svg.script:
var svg = document.getElementById("logo");
var malla = crearMalla(svg,1);

//render(svg, malla);

setInterval(function() {render(svg, malla);}, 1);


function render(ventana, malla) {
	limpiarVentana(ventana);
	mostrarMalla(ventana, malla);
	animacion(malla);
}



function crearMalla(svg, error=0.0) {
	var poligonos = svg.getElementsByTagName("polygon");
	var vertices = new Array();
	var triangulos = new Array();

	for (var i=0;i<poligonos.length;i++) {
		if (poligonos[i].classList.contains("render")) continue;
		var points = poligonos[i].getAttribute('points').split(" ");
		var v = new Array();

		while (points.length > 0) {
			  var x=points.shift();
			  var y=points.shift();
			  var vertice = -1;

		 	  for (var j=0;j<vertices.length;j++) {
			      if (distancia(x,y,vertices[j].x,vertices[j].y) <= error) {
				     vertice = j;
					 break;
					}
			  }

			  if (vertice == -1) {
				  vertice = vertices.length;
				  vertices.push(crearVertice(x,y));
			  }

			  v.push(vertice);
		}
		triangulos.push(crearTriangulo(v));
	}

	console.log(vertices.length, triangulos.length);

	return {'vertices':vertices, 'triangulos':triangulos};
}



function mostrarMalla(v, m) {
	for (var i=0;i<m.vertices.length;i++) {
		var vertice = m.vertices[i];
		var punto = crearCirculo(vertice.x, vertice.y, 1, "punto");
        punto.setAttribute('style', "opacity:"+vertice.opacity);
		v.appendChild(punto);
	}

	for (var i=0;i<m.triangulos.length;i++) {
		var t = m.triangulos[i];
		var triangulo = crearPoligono(t.vertices, m.vertices, "triangulo");
        triangulo.setAttribute('style', "opacity:"+t.opacity);
		v.appendChild(triangulo);
	}
}



function limpiarVentana(svg) {
	var elementos = svg.getElementsByClassName("render");
	while (elementos[0]) 
		elementos[0].parentNode.removeChild(elementos[0]);
}



function animacion(m) {
	//console.log(this.estado);

	if (typeof this.estado === 'undefined') {
		this.estado = 0;
		this.triangulosA = new Array();
		this.verticesA = new Array();
		this.deformacion = 1;
		}

	switch (this.estado) {
		case 0: if (fade(m.vertices,1))
					this.estado++;
				break;

		case 1: if (fade(m.triangulos, 1))
					this.estado++;
				break;

		case 2: if (fade(m.vertices, 0))
				   this.estado++;
				break;

		case 3:	if (Math.random()<.1) {
					this.deformacion++;			
					//limpiarVentana(svg);
					malla = crearMalla(svg, this.deformacion);
					setOpacity(malla.triangulos,1);
				}

				if (this.deformacion > 50) {
					malla = crearMalla(svg, 1);
					this.estado = 0;
					this.deformacion = 1;
				}
				break;

		case 4: if (Math.random()<.1) {
					var v = Math.floor(Math.random()*m.vertices.length);
					var t = buscarTriangulosVertice(m,v);
					for (var i=0;i<t.length;i++) {
						t[i].opacity = 0.0;						
					    this.triangulosA.push(t[i]);
						//console.log(">>",this.triangulosA.length);
					}
				}

				if (Math.random()<.5) {
					var t = this.triangulosA.random();
					if (t) {
						t.opacity = 1;
						this.triangulosA.remove(t);
					}
				}
				break;

		}
}


Array.prototype.remove = function(e) {
	var index = this.indexOf(e);
	if (index !== -1) this.splice(index, 1);
    return this;
}

Array.prototype.random = function() {
	return (this[Math.floor(Math.random()*this.length)]);
}


function moverVertices(m) {
	for (var i=0;i<m.vertices.length;i++) {
			v = m.vertices[i];

			var x = parseFloat(v.x);
			var y = parseFloat(v.y);

			v.x = x + Math.random()-.5;
			v.y = y + Math.random()-.5;		
		}	
}




function fade(o, objetivo) {
	var contador = o.length;

	for (var i=0, n=10;i<o.length && n>0;i++) {
		var obj = o[i];

		if (objetivo == 1) {		
			if (obj.opacity == 0.0) {
				obj.opacity = Math.random()/10;
				n--;
			}
			else obj.opacity += Math.random()/10;

			if (obj.opacity > 1) contador--;
		}			
		else {			
			obj.opacity -= Math.random()/10;		
			if (obj.opacity < 0) contador--;		
		}
	}

	return !contador;
}

function setOpacity(o, valor) {
	for (var i=0;i<o.length;i++)
		o[i].opacity = valor;
}


function distancia(x1,y1,x2,y2) {
 var a = x1 - x2;
 var b = y1 - y2;

 return Math.sqrt( a*a + b*b );
}

function crearTriangulo(vertices) {
 var obj = {'vertices':vertices};
 obj.opacity = 0.0;
 obj.estado = 0;

 obj.tieneVertice = function (v) {
	for (var i=0;i<this.vertices.length;i++)
		if (this.vertices[i] == v) 
			return true;
	return false;
 }

 return obj;
}

function crearVertice(x,y) {
 var obj = {'x':x, 'y':y};
 obj.opacity = 0.0;
 obj.estado = 0;
 obj.x0 = x;
 obj.y0 = y;


 obj.reset = function() {
	this.x = parseFloat(this.x0); 
	this.y = parseFloat(this.y0);
	};

 return obj;
}


function crearCirculo(x, y, r=1, clase="") {
	var circulo = document.createElementNS("http://www.w3.org/2000/svg", 'circle');
	circulo.setAttribute('cx', x);
	circulo.setAttribute('cy', y);
	circulo.setAttribute('r', r);
	circulo.setAttribute("class", "render "+clase);

	return circulo;
}

function crearPoligono(p, v, clase="") {
	var puntos = "";

	for (var i=0; i<p.length; i++) {
		var idv = p[i];
		var punto = v[idv];
		puntos = puntos + punto.x+" "+punto.y+" ";
	}

	var poligono = document.createElementNS("http://www.w3.org/2000/svg", 'polygon');
	poligono.setAttribute('points', puntos);
	poligono.setAttribute("class", "render "+clase);

	return poligono;
}


function resetTriangulo(t, m) {
	for (var i=0;i<t.vertices.length;i++)
	    m.vertices[t.vertices[i]].reset();
}


function buscarTriangulosVertice(m,v) {
	var t = new Array();

	for (var i=0;i<m.triangulos.length;i++)
		if (m.triangulos[i].tieneVertice(v))
			t.push(m.triangulos[i]);

	return t;
}



function hasClass(el, className)
{
	return !!el.className.match(new RegExp('(\\s|^)' + className + '(\\s|$)'));
}

function addClass(el, className)
{
	if (!hasClass(el, className))
    el.className += " " + className;
}

function removeClass(el, className)
{
	if (hasClass(el, className)) {
        var reg = new RegExp('(\\s|^)' + className + '(\\s|$)');
        el.className = el.className.replace(reg, ' ');
    }
}
